s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns_client = boto3.client('sns')
sqs_client = boto3.client('sqs')

def lambda_handler(event, context):
    function_name = os.environ.get('AWS_LAMBDA_FUNCTION_NAME', 'unknown')
    
    try:
        table_name = os.environ.get('DYNAMODB_TABLE', 'microservices-data')
        bucket_name = os.environ.get('S3_BUCKET', 'microservices-storage')
        topic_arn = os.environ.get('SNS_TOPIC_ARN', '')
        queue_url = os.environ.get('SQS_QUEUE_URL', '')
        
        timestamp = datetime.utcnow().isoformat()
        
        response_data = {
            'function': function_name,
            'timestamp': timestamp,
            'event': event
        }
        
        if 'action' in event:
            action = event['action']
            
            if action == 's3_write':
                key = event.get('key', f'data/{timestamp}.json')
                s3_client.put_object(
                    Bucket=bucket_name,
                    Key=key,
                    Body=json.dumps(event.get('data', {}))
                )
                response_data['s3_result'] = f'Written to s3://{bucket_name}/{key}'
            
            elif action == 's3_read':
                key = event.get('key')
                obj = s3_client.get_object(Bucket=bucket_name, Key=key)
                content = obj['Body'].read().decode('utf-8')
                response_data['s3_result'] = json.loads(content)
            
            elif action == 'dynamodb_write':
                table = dynamodb.Table(table_name)
                item = event.get('item', {})
                item['id'] = event.get('id', timestamp)
                item['timestamp'] = timestamp
                table.put_item(Item=item)
                response_data['dynamodb_result'] = f'Item written to {table_name}'
            
            elif action == 'dynamodb_read':
                table = dynamodb.Table(table_name)
                item_id = event.get('id')
                result = table.get_item(Key={'id': item_id})
                response_data['dynamodb_result'] = result.get('Item', {})
            
            elif action == 'sns_publish':
                message = event.get('message', 'Default message')
                subject = event.get('subject', 'Microservice Notification')
                sns_response = sns_client.publish(
                    TopicArn=topic_arn,
                    Message=json.dumps(message),
                    Subject=subject
                )
                response_data['sns_result'] = sns_response['MessageId']
            
            elif action == 'sqs_send':
                message = event.get('message', 'Default message')
                sqs_response = sqs_client.send_message(
                    QueueUrl=queue_url,
                    MessageBody=json.dumps(message)
                )
                response_data['sqs_result'] = sqs_response['MessageId']
            
            elif action == 'sqs_receive':
                messages = sqs_client.receive_message(
                    QueueUrl=queue_url,
                    MaxNumberOfMessages=event.get('max_messages', 1)
                )
                response_data['sqs_result'] = messages.get('Messages', [])
        
        return {
            'statusCode': 200,
            'body': json.dumps(response_data)
        }
    
    except Exception as e:
        print(f"Error in {function_name}: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': str(e),
                'function': function_name
            })
        }